INSERT INTO `iku` (`id`, `tahun`, `unitkey`, `no`, `sasaran_strategis`, `indikator_kinerja`, `img_form`, `formulasi`) VALUES
(1, 2018, 116, 1, 'Pengendalian internal terhadap tata kelola keuangan Pemerintah Daerah Meningkat', 'Tingkat Maturitas SPIP', 0, 'Rumus: menunjukkan tingkat maturitas penyelenggaraan SPIP.<br/>\r\nMaturity Level Penyelenggaraan SPIP adalah tingkat kematangan penyelenggaraan SPIP dalam mencapai tujuan pengendalian intern, yang ditandai oleh eksistensi control design yang bersifat hard control dan soft control.\r\nInterval Skor Maturity Level SPIP dengan karakteristik sebagai berikut:<br/>\r\nLevel 0, jika skor kurang dari 1,0 (0 < skor <1,0) tingkat maturitas belum ada<br/>\r\nLevel 1, jika skor 1,0 s/d kurang dari 2,0 (1,0 ? skor < 2,0) tingkat maturitas rintisan'),
(2, 2018, 44, 1, 'Tertib Administrasi Kependudukan meningkat', 'Cakupan masyarakat yang mendapatkan pelayanan administrasi kependudukan', 0, 'Rumus:<br/>\r\n(&Sigma; KTP yang diterbitkan sampai dengan tahun n /&Sigma;  wajib KTP sampai dengan tahun n)x100%<br/>\r\n(&Sigma; KK yang diterbitkan sampai dengan tahun n /&Sigma; KK terdaftar sampai dengan tahun n)x 100%<br/>\r\nTipologi data: Komulatif'),
(8, 2018, 42, 1, 'Kualitas layanan bidang administrasi dan keuangan bagi Anggota DPRD meningkat', 'Persentase anggota DPRD yang puas terhadap layanan tentang administrasi dan keuangan', 0, 'Rumus:<br/>\r\n(Total dari nilai persepsi per unsur /Total unsur yang terisi )x Nilai penimbang <br/>\r\n<br/>\r\nDimana bobot nilai rata-rata tertimbang = Jumlah bobot dibagi jumlah unsur = 1 dibagi 14 = 0,071<br/>\r\nUntuk memudahkan interprestasi terhadap penilaian IKM antara 25-100, maka hasil penilaian tersebut dikonversikan dengan nilai dasar 25 dengan rumus: <br/>\r\nIKM Unit Pelayanan x 25 Responden yang disurvei adalah seluruh anggota DPRD<br/>\r\nTipologi data: Non komulatif'),
(9, 2018, 43, 1, 'Layanan prasarana transportasi meningkat', 'Indeks jalan kabupaten dan jembatan', 0, 'Rumus:<br/>\r\nIndeks jalan kabupaten dan jembatan dihitung berdasarkan hasil rata-rata capaian dari:<br/>\r\n1. Persentase panjang jalan kabupaten dalam kondisi baik; dan<br/>\r\n2. Persentase jembatan dalam kondisi baik.<br/>\r\nKeterangan:<br/>\r\nJalan kabupaten dalam kondisi baik adalah tersedianya jalan yang menjamin kendaraan dapat berjalan dengan selamat dan nyaman serta sesuai dengan kecepatan rencana.<br/>\r\nJembatan kabupaten dalam kondisi baik adalah tersedianya jembatan yang menjamin kendaraan dapat melaluinya dengan selamat dan nyaman.<br/>\r\nJalan dan jembatan yang dimaksud adalah jalan dan jembatan menjadi kewenangan kabupaten.<br/>\r\nDinas Pekerjaan Umum, Perumahan Rakyat, dan Kawasan Permukiman<br/>\r\nTipologi data: Komulatif'),
(3, 2018, 73, 1, 'Pengembangan Ragam budaya meningkat', 'Jumlah Ragam budaya yang dikembangkan/difasilitasi', 0, 'Rumus:\r\nMenunjukkan jumlah ragam budaya yang dikembangkan/difasilitasi dalam satu tahun Dinas Kebudayaan\r\nLaporan Tahunan\r\nYang dimaksud dengan ragam budaya adalah keanekaragaman budaya yang dimiliki Kabupaten Gunungkidul antara lain meliputi kesenian, permainan tradisional, adat dan tradisi, bahasa jawa, sastra dan aksara jawa, kerajinan, kuliner, pengobatan tradisional, penataan ruang, bangunan, dan warisan budaya\r\n<br/>Tipologi data: Non komulatif'),
(4, 2018, 38, 1, 'Derajat Kesehatan Masyarakat Meningkat', 'Angka harapan hidup', 0, 'Angka perkiraan lama hidup rata-rata dengan asumsi tidak ada perubahan pola mortalitas menurut umur\r\nTipe data: Non Komulatif'),
(5, 2018, 41, 1, 'Penyelenggaraan Pemerintahan daerah Meningkat', 'Nilai Capaian Kinerja Penyenggaraan Pemerintahan Daerah', 0, 'Rumus:<br/>\r\nMenunjukkan nilai capaian kinerja penyelenggaraan Pemerintahan Daerah.<br/>\r\nStatus/Kategori Kinerja Penyelenggaraan Pemerintahan Daerah<br/>\r\nNilai 0,00-1,00 : Rendah<br/>\r\nNilai 1,00-2,00 : Sedang<br/>\r\nNilai 2,00-3,00 : Tinggi<br/>\r\nNilai 3,00-4,00 : Sangat Tinggi<br/>\r\nTipologi data: Non komulatif'),
(6, 2018, 41, 2, 'Nilai AKIP Pemerintah Daerah Meningkat', 'Nilai AKIP Pemerintah Daerah', 0, 'Rumus:<br/>\r\nMenunjukkan nilai AKIP Pemerintahan Daerah.<br/>\r\nKategori tingkat akuntabilitas kinerja:<br/>\r\nNilai >90-100 : Sangat memuaskan  (AA)<br/>\r\nNilai >80-90 : Memuaskan (A)<br/>\r\nNilai >70-80 : Sangat Baik (BB) <br/>\r\nNilai >60-70 : Baik (B)<br/>\r\nNilai >50-60 : Cukup (Memadai) (CC)<br/>\r\nNilai >30-50 : Kurang (C)<br/>\r\nNilai 0 – 30 : Sangat Kurang (D)<br/>\r\n\r\nTipologi data: Non komulatif'),
(10, 2018, 43, 3, 'Penanganan infrastruktur irigasi meningkat', 'Persentase luasan Daerah Irigasi (DI) yang teraliri air irigasi', 0, 'Rumus:<br/>\r\n(&Sigma; luasan Daerah Irigasi (DI) yang teraliri air irigasi / &Sigma; luasan Daerah Irigasi)x100%\r\n<br/>\r\nTipologi data: Non komulatif'),
(7, 2018, 41, 3, 'Kepuasan masyarakat terhadap penyelenggaraan pelayanan publik meningkat', 'Nilai IKM Kabupaten', 0, 'Rumus IKM:<br/>\r\n(Total dari nilai persepsi per unsur /Total unsur yang terisi)x Nilai penimbang<br/>\r\nDimana bobot nilai rata-rata tertimbang = Jumlah bobot dibagi jumlah unsur = 1 dibagi 14 = 0,071<br/>\r\nUntuk memudahkan interprestasi terhadap penilaian IKM antara 25-100, maka hasil penilaian tersebut dikonversikan dengan nilai dasar 25 dengan rumus:<br/>\r\nIKM Unit Pelayanan x 25<br/>\r\nTipologi data: Non komulatif'),
(30, 2018, 43, 2, 'Penanganan Lingkungan Permukiman meningkat', 'Indeks Penyehatan lingkungan', 0, 'Rumus:<br/>\r\nIndeks Penyehatan lingkungan dihitung berdasarkan hasil rata-rata capaian dari:<br/>\r\n1. Persentase cakupan rumah tangga yang memiliki akses sistem pengelolaan air limbah<br/>\r\n2. Persentase terlayani air minum layak<br/>\r\n3. Persentase luas kawasan kumuh<br/>\r\n4. Persentase Rumah Tidak Layak Huni (RTLH)<br/>\r\n5. Persentase tingkat hunian rumah susun<br/>\r\nTipologi data: Komulatif<br/>'),
(12, 2018, 49, 1, 'Kualitas Pengelolaan Keuangan Daerah Meningkat', 'Indeks Pengelolaan Keuangan', 0, 'Rumus:<br/>\r\nIndeks Pengelolaan Keuangan dihitung berdasarkan hasil rata-rata capaian dari:<br/>\r\n1. Persentase PD yang menyampaikan Laporan Keuangan dengan benar dan tepat waktu<br/>\r\n2. Tingkat Ketepatan Waktu Penyampaian RAPBD (Minggu pertama bulan oktober tahun sebelumnya)<br/>\r\nPersentase penyelesaian SP2D secara tepat waktu<br/><br/>\r\n\r\nTipologi data: Non komulatif'),
(13, 2018, 49, 2, 'Kualitas Penatausahaan Aset Daerah meningkat', 'Indeks Pengelolaan Aset Daerah', 0, 'Rumus:<br/>\r\nIndeks Pengelolaan Aset Daerah dihitung berdasarkan hasil rata-rata capaian dari:<br/>\r\n1. Persentase Aset yang dilaporkan ke neraca;<br/>\r\n2. Tingkat Ketepatan Waktu Penyampaian Laporan Aset semester satu dan semester dua<br/>\r\nTipologi data: Non komulatif'),
(14, 2018, 71, 1, 'Pemenuhan kebutuhan lahan untuk kepentingan publik meningkat', 'Persentase pemenuhan kebutuhan lahan untuk kepentingan publik', 0, 'Rumus:<br/>\r\n(&Sigma; pemenuhan kebutuhan luasan lahan untuk kepentingan publik / &Sigma; kebutuhan luasan lahan untuk kepentingan publik)x100%\r\n<br/>\r\nTipologi data: Non komulatif'),
(15, 2018, 71, 2, 'Kualitas Perencanaan Tata Ruang Meningkat', 'Jumlah dokumen tata ruang yang sudah ditetapkan menjadi Peraturan Daerah (PERDA)', 0, 'Rumus:<br/>\r\nMenunjukkan jumlah dokumen tata ruang yang sudah ditetapkan menjadi Peraturan Daerah (PERDA)<br/>\r\nTipologi data: Non komulatif'),
(16, 2018, 71, 2, 'Kualitas Perencanaan Tata Ruang Meningkat', 'Nilai Kinerja Penyelenggaraan Penataan Ruang', 0, 'Rumus:<br/>\r\nNilai Kinerja Penyelenggaraan Penataan Ruang adalah hasil nilai rata-rata dari aspek penilian yang terdiri:<br/>\r\n1. Pengaturan Penataan Ruang dengan bobot 35%;<br/>\r\n2. Pembinaan Penataan Ruang dengan bobot 20%; dan<br/>\r\n3. Pelaksanaan Penataan Ruang dengan bobot 45%.<br/>\r\nKriteria/Kategori Kinerja Penyelenggaraan Penataan Ruang:<br/>\r\nNilai <=55% : Kurang<br/>\r\nNilai >55% dan <=69% : Cukup<br/>\r\nNilai >69% dan <=85% : Baik<br/>\r\nNilai > 85% : Memuaskan<br/>\r\nTipologi data: Non komulatif'),
(17, 2018, 72, 1, 'Kualitas Pelayanan Komunikasi dan Informatika pemerintah meningkat', 'Indeks kepuasan layanan komunikasi dan informatika pemerintah', 0, 'Rumus: <br/>\r\nIndeks kepuasan layanan komunikasi dan informatika pemerintah dihitung berdasarkan hasil rata-rata capaian dari:<br/>\r\n1. Persentase peningkatan kualitas layanan jaringan komunikasi data dan informatika<br/>\r\n2. Persentase PD yang memiliki layanan informasi yang dikelola secara aktif<br/>\r\n3. Persentase layanan keamanan informatika<br/>\r\n4. Persentase data dasar yang tersedia untuk perencanaan<br/>\r\nTipologi data: Komulatif'),
(18, 2018, 77, 1, 'Daya saing pariwisata meningkat', 'Jumlah Kunjungan wisatawan nusantara dan wisatawan mancanegara', 0, 'Rumus:<br/>\r\nMenunjukkan jumlah kunjungan wisman dan wisnus dalam kurun waktu satu tahun<br/>\r\nTipologi data: Komulatif'),
(19, 2018, 77, 1, 'Daya saing pariwisata meningkat', 'Lama tinggal wisatawan nusantara dan wisatawan mancanegara', 0, 'Rumus:<br/>\r\n(Jumlah kamar yang terjual / tamu yang check in) x 100% <br/>\r\nTipologi data: Non komulatif'),
(20, 2018, 79, 1, 'Penyandang Masalah Kesejahteraan Sosial (PMKS) yang terlayani meningkat', 'Persentase PMKS yang memperoleh bantuan sosial untuk pemenuhan kebutuhan dasar', 0, '(Jumlah PMKS yang memperoleh bantuan sosial untuk pemenuhan kebutuhan dasar/ PMKS)x100%\r\n<br/>\r\nYang dimaksud dengan kebutuhan dasar adalah kebutuhan yang mencakup air bersih, nutrisi, perawatan kesehatan, pendidikan, sandang, dan papan<br/>\r\nTipologi data: Non komulatif'),
(21, 2018, 107, 1, 'Aparatur yang kompeten dan profesional meningkat', 'Indeks profesionalitas ASN', 0, 'Rumus:<br/>\r\nIndeks profesionalitas ASN dihitung berdasarkan hasil rata-rata capaian dari:<br/>\r\n1. Persentase kenaikan pangkat dan pensiun PNS tepat waktu serta pengangkatan dan pemindahan PNS yang sesuai formasi<br/>\r\n2. Persentase Pengiriman Peserta Diklat dan Tugas Belajar sesuai kebutuhan<br/>\r\n3. Persentase Pelanggaran dan Kasus PNS yang terselesaikan<br/>\r\nTipoligi Data: Non komulatif'),
(22, 2018, 108, 1, 'Keselamatan pasien meningkat', 'Indeks Keselamatan pasien', 0, 'Rumus:<br/>\r\nIndeks keselamatan pasien, dihitung dengan pembobotan unsur-unsur:<br/>\r\n1. Pemasangan gelang identitas pasien rawat inap;<br/>\r\n2. Ketepatan waktu pelaporan hasil laboratorium kritis;<br/>\r\n3. Pemasangan label hight alert;<br/>\r\n4. Penandaan sisi lokasi operasi/site marking;<br/>\r\n5. Enam langkah cuci tangan dengan benar;<br/>\r\n6. Pemasangan tanda risiko jatuh skor tinggi pada pasien rawat inap;<br/>\r\nMasing-masing unsur diberikan bobot yang sama.<br/>\r\nTipologi data: Non komulatif'),
(23, 2018, 110, 1, 'Kesesuaian program pembangunan daerah', 'Indeks kesesuaian program', 0, 'Rumus:<br/>\r\nIndeks kesesuaian program dihitung berdasarkan hasil rata-rata capaian dari:<br/>\r\n1. Persentase kesesuaian program dalam RKPD terhadap RPJMD<br/>\r\n2. Persentase kesenjangan capaian target kinerja dalam perencanaan pembangunan jangka menengah dan tahunan daerah<br/>\r\n3. Persentase kesesuaian program dalam Renja PD Bidang Fisik dan Prasarana terhadap RKPD dan APBD, serta Program dalam Renstra PD terhadap RPJMD<br/>\r\n4. Persentase kesesuaian program dalam Renja PD Bidang Pemerintahan, Sosial dan Budaya terhadap RKPD dan APBD, serta Program dalam Renstra PD terhadap RPJMD<br/>\r\n5. Persentase kesesuaian program dalam Renja PD Bidang Perekonomian terhadap RKPD dan APBD, serta Program dalam Renstra PD terhadap RPJMD<br/>\r\nTipologi data: Non komulatif'),
(24, 2018, 110, 2, 'Kerjasama Penelitian dalam Pembangunan Daerah meningkat', 'Hasil kerjasama penelitian yang ditindaklanjuti menjadi kebijakan', 0, 'Rumus:<br/>\r\nMenunjukkan hasil kerjasama penelitian yang ditindaklanjuti menjadi kebijakan<br/>\r\nTipologi data: Non komulatif'),
(25, 2018, 111, 1, 'Penyediaan sarana dan prasarana perhubungan meningkat', 'Persentase ketersediaan fasilitas lalu lintas', 0, 'Rumus:<br/>\r\n(Jumlah fasilitas lalu lintas yang tersedia / Jumlah kebutuhan fasilitas lalu lintas )x 100%<br/>\r\nYang dimaksud dengan fasilitas lalu lintas terdiri dari: traffic light, cermin cembung, rambu pendahulu pengarah jurusan, marka jalan, guardrail, deliniator, dan lampu penerangan jalan umum<br/>\r\nTipologi data: Komulatif'),
(26, 2018, 112, 1, 'Kualitas lingkungan hidup meningkat', 'Indeks Kualitas Lingkungan Hidup', 0, 'Rumus: <br/>\r\n(IPU x 30%)+(IPA x 30%)+(ITH x 40%)<br/>\r\nIPU = Indeks Pencemaran Udara<br/>\r\nIPA = Indeks Pencemaran Air<br/>\r\nITH = Indeks Tutupan Hutan<br/>\r\nMenunjukkan angka indeks dari unsur-unsur kondisi udara, air, dan tutupan hutan/vegetasi<br/>\r\nTipologi data: Non komulatif'),
(27, 2018, 112, 1, 'Kualitas lingkungan hidup meningkat', 'Penurunan luasan lahan kritis yang terehabilitasi', 0, 'Rumus:<br/>\r\n&Sigma; luasan lahan kritis dikurangi 	&Sigma; luasan lahan kritis yang terehabilitasi<br/>\r\nDinas Lingkungan Hidup<br/>\r\nLaporan tahunan<br/>\r\nTipologi data: Non komulatif'),
(28, 2018, 41, 4, 'Pertumbuhan ekonomi meningkat', 'Angka pertumbuhan ekonomi', 0, 'Rumus:<br/>\r\nG=((PDRB<sub>1</sub>-PDRB<sub>0</sub>)/PDRB<sub>0</sub>)x100%<br/>\r\n\r\nG =Laju pertumbuhan ekonomi<br/>\r\nPDRB<sub>1</sub>=PPDRB ADHK pada suatu tahun<br/>\r\nPDRB<sub>0</sub>=PPDRB ADHK pada tahun sebelumnya<br/>\r\n<br/>\r\nTipologi data: Non komulatif'),
(29, 2018, 43, 4, 'Penyediaan sarana dan prasarana aparatur yang baik meningkat', 'Persentase sarana dan prasarana pemerintah baik', 0, 'Rumus:<br/>\r\n(&Sigma; sarana dan prasarana pemerintah dalam kondisi baik / &Sigma; sarana dan prasarana pemerintah)x100%\r\n<br/>Yang dimaksud sarana dan prasarana pemerintah adalah laboratorium dan alat berat\r\n<br/>\r\nTipologi data: Non komulatif'),
(31, 2018, 37, 1, 'Prestasi Pemuda dan olahraga meningkat', 'Persentase peningkatan Prestasi Pemuda dan olahraga di tingkat Provinsi,\r\nRegional, Nasional, dan Internasional', 0, 'Rumus:<br/>\r\n((&Sigma; Prestasi Pemuda dan olahraga di tingkat Provinsi, Regional, Nasional, dan\r\nInternasional tahun ini (tahun n) - &Sigma; Prestasi\r\nPemuda dan olahraga di tingkat Provinsi, Regional, Nasional, dan Internasional tahun\r\nlalu (tahun n-1))/ &Sigma; Prestasi Pemuda dan olahraga di tingkat\r\nProvinsi, Regional, Nasional, dan\r\nInternasional tahun lalu (tahun n-1))x100% <br/>\r\nTipologi data: Non komulatif'),
(32, 2018, 37, 2, 'Kualitas Pendidikan Meningkat', 'Rata-rata lama sekolah', 1, NULL),
(33, 2018, 37, 2, 'Kualitas Pendidikan Meningkat', 'Harapan rata-rata lama sekolah', 1, NULL),
(34, 2018, 117, 1, 'Kualitas pelayanan perizinan meningkat', 'Indeks ketepatan waktu pelayanan perizinan dan non perizinan', 0, 'Rumus:<br/>\r\n&Sigma;  nilai unsur kecepatan pelayanan /&Sigma;  kuesioner yang terisi\r\nTipologi data: Non Komulatif'),
(35, 2018, 117, 2, 'Pertumbuhan investasi nasional dan lokal meningkat', 'Pertumbuhan nilai investasi nasional dan lokal', 0, 'Rumus:<br/>\r\n((Realisasi nilai investasi tahun n – Realisasi nilai investasi tahun (n-1))/ Realisasi nilai investasi tahun n)x100% \r\n<br/>\r\nTipologi data: Komulatif'),
(36, 2018, 120, 1, 'Kualitas penyelenggaraan Pemerintahan Desa meningkat', 'Persentase desa yang tertib dalam penyelenggaraan pemerintahan', 1, NULL),
(37, 2018, 120, 2, 'Pembangunan gender dan anak meningkat', 'Persentase perempuan dan anak korban kekerasan yang mendapatkan layanan rehabilitasi', 1, NULL),
(38, 2018, 120, 3, 'Peserta KB aktif meningkat', 'Persentase Cakupan sasaran Pasangan Usia Subur (PUS) menjadi peserta KB aktif', 1, NULL),
(39, 2018, 120, 4, 'Pemberdayaan masyarakat meningkat', 'Persentase peningkatan swadaya masyarakat dalam pembangunan desa', 1, NULL),
(40, 2018, 123, 1, 'Kesejahteraan masyarakat petani meningkat', 'Pendapatan per kapita sektor pertanian (PDRB sektor pertanian : Jumlah penduduk di sektor pertanian)', 0, 'Rumus:\r\nPendapatan sektor pertanian yang terdiri dari padi, jagung, kedelai, kakao, kelapa, mete, tembakau, bawang merah, cabe besar, pengiriman ternak keluar, hasil ternak (daging sapi, kambing, ayam, dan telur)<br/>\r\nTipologi data: Non Komulatif'),
(41, 2018, 123, 1, 'Kesejahteraan masyarakat petani meningkat', 'Jumlah kelompok tani yang telah menerapkan Agribisnis terpadu', 0, 'Rumus:<br/>\r\nMenunjukkan jumlah kelompok tani yang telah menerapkan Agribisnis terpadu<br/>\r\nTipologi data: Komulatif'),
(42, 2018, 123, 2, 'Ketersediaan, distribusi, dan konsumsi pangan meningkat', 'Pertumbuhan Ketersediaan, distribusi, dan konsumsi pangan:<br/>\r\n1. Ketersediaan Pangan (beras)<br/>', 0, '1. Hasil konversi produksi padi ke beras<br/>\r\nRumus = &Sigma; produksi padi x 62,7%<br/>\r\n2. Ketersediaan pangan beras dengan melihat konsumsi beras masyarakat berdasar PPH tahun 2016 = 81,7 yang diasumsikan turun 3 point setiap tahunnya dikalikan jumlah penduduk<br/>\r\nRumus = ketersediaan beras – (PPH berlaku) x jumlah penduduk<br/>\r\nTipologi data: Komulatif'),
(43, 2018, 123, 2, 'Ketersediaan, distribusi, dan konsumsi pangan meningkat', '2. Harga pangan yang terjangkau dan terkendali', 0, 'Harga pangan yang terjangkau terdiri dari: IR I, IR II, jagung pipil kering, dan kedelai lokal'),
(44, 2018, 123, 2, 'Ketersediaan, distribusi, dan konsumsi pangan meningkat', '3. Nilai PPH (Pola Pangan Harapan)', 0, 'Hasil analisis survey konsumsi pangan'),
(45, 2018, 123, 2, 'Ketersediaan, distribusi, dan konsumsi pangan meningkat', '4. Nilai NBM (Neraca Bahan Makanan)', 0, 'Hasil analisis survey peredaran pangan'),
(46, 2018, 123, 3, 'Produksi Tanaman Pangan Meningkat', 'Tingkat produksi komoditas unggulan tanaman pangan:<br/>\r\nPadi <br/>\r\nJagung<br/>\r\nKedelai<br/>\r\nUbi kayu<br/>', 0, 'Rumus:<br/>\r\nProduktivitas x luas panen<br/>\r\nYang dimaksud komoditas unggulan tanaman pangan yaitu: padi, jagung, kedelai, dan ubi kayu<br/>\r\nTipologi data: Non Komulatif'),
(47, 2018, 123, 4, 'Produksi hasil perkebunan dan hortikultura unggulan meningkat', 'Tingkat produksi hasil perkebunan dan hortikultura unggulan:<br/>\r\nKakao<br/>\r\nMete<br/>\r\nTembakau<br/>\r\nKelapa (butir)<br/>\r\nBawang merah<br/>\r\nCabe', 0, 'Rumus:<br/>\r\nProduktivitas x luas panen<br/>\r\nYang dimaksud komoditas unggulan tanaman perkebunan dan hortikultra seperti kakao, mete, tembakau, kelapa, bawang merah, dan cabai.<br/>\r\nTipologi data: Non Komulatif'),
(48, 2018, 123, 5, 'Produksi komoditas peternakan unggulan meningkat', 'Jumlah Populasi ternak dan Produksi daging dan telur', 0, 'Rumus:<br/>\r\nJumlah populasi ternak berdasarkan hasil pendataan terhadap sapi potong, kambing, dan ayam buras<br/>\r\n\r\nRumus Produksi Daging:<br/>\r\nPD = Ko x St<br/>\r\nKeterangan:<br/>\r\nPD = Produksi Daging<br/>\r\nKo = Berat karkas (dengan edible offal)<br/>\r\nSt = Jumlah pemotongan ternak pada tahun yang bersangkutan<br/>\r\nRumus Produksi Telur:<br/>\r\nPT = Po x p x % Betina produktif<br/>\r\nKeterangan:<br/>\r\nPT = Produksi Telur<br/>\r\nP = parameter produksi telur unggas (butir/ ekor/tahun)<br/>\r\n% Betina Produktif = ayam petelur (70%), ayam buras (34,4%), itik (66,45%)<br/>\r\nTipologi data: Non Komulatif');
INSERT INTO `mainmenu` (`id_main`, `nama_menu`, `link`, `aktif`, `adminmenu`) VALUES
(2, 'Beranda', '', 'Y', 'N'),
(3, 'Profil', '#', 'Y', 'N'),
